import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    orange: '#fb923c',
    green: '#a3e635',
  },
  font: "'JetBrains Mono', monospace",
};

const SmallBtn = ({ onClick, children }) => (
  <button
    onClick={onClick}
    style={{
      background: 'none',
      border: '1px solid ' + theme.colors.border,
      borderRadius: 4,
      width: 18,
      height: 18,
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: 13,
      fontWeight: 700,
      fontFamily: theme.font,
      color: theme.colors.textSecondary,
      padding: 0,
      lineHeight: 1,
    }}
  >
    {children}
  </button>
);

export default function App() {
  const [a, setA] = useState([1, 0, 0]);
  const [b, setB] = useState([0, 1, 0]);
  const [hovered, setHovered] = useState(-1);

  const cross = useMemo(
    () => [
      a[1] * b[2] - a[2] * b[1],
      a[2] * b[0] - a[0] * b[2],
      a[0] * b[1] - a[1] * b[0],
    ],
    [a, b]
  );

  const isZero = cross[0] === 0 && cross[1] === 0 && cross[2] === 0;
  const dotAC = a[0] * cross[0] + a[1] * cross[1] + a[2] * cross[2];
  const dotBC = b[0] * cross[0] + b[1] * cross[1] + b[2] * cross[2];
  const magC = Math.sqrt(cross[0] ** 2 + cross[1] ** 2 + cross[2] ** 2);

  const updateVec = (setter, idx, delta) => {
    setter((prev) => {
      const next = [...prev];
      next[idx] = Math.max(-3, Math.min(3, next[idx] + delta));
      return next;
    });
  };

  const svgW = 560;
  const svgH = 220;
  const cx = svgW / 2;
  const cy = svgH / 2 + 15;
  const sc = 36;

  const project = (x, y, z) => [
    cx + (x * 0.866 - y * 0.866) * sc,
    cy + (x * 0.5 + y * 0.5 - z * 1.0) * sc,
  ];

  const origin = project(0, 0, 0);

  const renderArrow = (vec, color, label, dashed) => {
    const [px, py] = project(vec[0], vec[1], vec[2]);
    const dx = px - origin[0];
    const dy = py - origin[1];
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len < 3) return null;
    const ux = dx / len;
    const uy = dy / len;
    const hl = 10;
    const hw = 5;
    const bx = px - ux * hl;
    const by = py - uy * hl;
    return (
      <g key={label}>
        <line
          x1={origin[0]}
          y1={origin[1]}
          x2={bx}
          y2={by}
          stroke={color}
          strokeWidth={dashed ? 1.5 : 2.5}
          strokeLinecap="round"
          strokeDasharray={dashed ? '6,4' : 'none'}
          style={{ transition: 'all 0.3s ease' }}
        />
        <polygon
          points={[
            px + ',' + py,
            (bx - uy * hw) + ',' + (by + ux * hw),
            (bx + uy * hw) + ',' + (by - ux * hw),
          ].join(' ')}
          fill={color}
          opacity={dashed ? 0.7 : 1}
          style={{ transition: 'all 0.3s ease' }}
        />
        <text
          x={px + ux * 16}
          y={py + uy * 16}
          fill={color}
          fontSize={12}
          fontWeight={700}
          fontFamily={theme.font}
          textAnchor="middle"
          dominantBaseline="central"
          style={{ transition: 'all 0.3s ease' }}
        >
          {label}
        </text>
      </g>
    );
  };

  const renderAxis = (vec, label) => {
    const [px, py] = project(vec[0] * 3.8, vec[1] * 3.8, vec[2] * 3.8);
    const [nx, ny] = project(vec[0] * -1.5, vec[1] * -1.5, vec[2] * -1.5);
    return (
      <g key={label}>
        <line
          x1={nx}
          y1={ny}
          x2={px}
          y2={py}
          stroke={theme.colors.border}
          strokeWidth={1}
          strokeDasharray="3,3"
        />
        <text
          x={px + (px > cx ? 10 : -10)}
          y={py + (py > cy ? 10 : -6)}
          fill={theme.colors.textMuted}
          fontSize={11}
          fontFamily={theme.font}
          textAnchor="middle"
          dominantBaseline="central"
        >
          {label}
        </text>
      </g>
    );
  };

  const pa = project(a[0], a[1], a[2]);
  const pb = project(b[0], b[1], b[2]);
  const pab = project(a[0] + b[0], a[1] + b[1], a[2] + b[2]);

  const showParallelogram = !isZero;

  const presets = [
    { name: 'i x j', a: [1, 0, 0], b: [0, 1, 0] },
    { name: 'j x i', a: [0, 1, 0], b: [1, 0, 0] },
    { name: 'Parallel', a: [1, 2, 0], b: [2, 4, 0] },
    { name: 'General', a: [1, 2, 3], b: [2, -1, 1] },
  ];

  const terms = [
    { label: 'x', t1: [a[1], b[2]], t2: [a[2], b[1]], ai1: 1, bi1: 2, ai2: 2, bi2: 1 },
    { label: 'y', t1: [a[2], b[0]], t2: [a[0], b[2]], ai1: 2, bi1: 0, ai2: 0, bi2: 2 },
    { label: 'z', t1: [a[0], b[1]], t2: [a[1], b[0]], ai1: 0, bi1: 1, ai2: 1, bi2: 0 },
  ];

  const VecEditor = ({ label, vec, setter, color }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: 3 }}>
      <span
        style={{
          color: color,
          fontWeight: 700,
          fontSize: 15,
          minWidth: 14,
        }}
      >
        {label}
      </span>
      <span style={{ color: theme.colors.textMuted, fontSize: 13 }}>=[</span>
      {vec.map((v, i) => (
        <React.Fragment key={i}>
          <SmallBtn onClick={() => updateVec(setter, i, -1)}>-</SmallBtn>
          <span
            style={{
              color: color,
              fontSize: 15,
              fontWeight: 600,
              width: 18,
              textAlign: 'center',
              display: 'inline-block',
              transition: 'all 0.2s',
            }}
          >
            {v}
          </span>
          <SmallBtn onClick={() => updateVec(setter, i, 1)}>+</SmallBtn>
          {i < 2 && (
            <span
              style={{
                color: theme.colors.textMuted,
                margin: '0 1px',
                fontSize: 12,
              }}
            >
              ,
            </span>
          )}
        </React.Fragment>
      ))}
      <span style={{ color: theme.colors.textMuted, fontSize: 13 }}>]</span>
    </div>
  );

  let insight = '';
  const aIsZero = a[0] === 0 && a[1] === 0 && a[2] === 0;
  const bIsZero = b[0] === 0 && b[1] === 0 && b[2] === 0;
  if (aIsZero || bIsZero) {
    insight =
      'One vector is zero, so the cross product is zero. No direction is perpendicular to nothing!';
  } else if (isZero) {
    insight =
      'Cross product is zero! The vectors are parallel - they span no area, so no perpendicular vector exists.';
  } else if (cross[0] === 0 && cross[1] === 0 && cross[2] !== 0) {
    insight =
      'Result points purely along z! Both inputs lie in the xy-plane, so their cross product is perpendicular to it.';
  } else if (
    JSON.stringify(a) === JSON.stringify([0, 1, 0]) &&
    JSON.stringify(b) === JSON.stringify([1, 0, 0])
  ) {
    insight =
      'Notice: j x i = -k, but i x j = k. The cross product is anti-commutative: a x b = -(b x a)!';
  } else {
    insight =
      'a . (a x b) = ' +
      dotAC +
      ', b . (a x b) = ' +
      dotBC +
      '. Both zero - the result is perpendicular to both inputs!';
  }

  return (
    <div
      style={{
        fontFamily: theme.font,
        background: theme.colors.background,
        color: theme.colors.text,
        maxWidth: 600,
        margin: '0 auto',
        padding: '12px 16px',
        maxHeight: 500,
        overflow: 'hidden',
      }}
    >
      {/* Title + Presets */}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 6,
        }}
      >
        <div style={{ fontSize: 16, fontWeight: 700 }}>3D Cross Product</div>
        <div style={{ display: 'flex', gap: 4 }}>
          {presets.map((p) => (
            <button
              key={p.name}
              onClick={() => {
                setA(p.a);
                setB(p.b);
              }}
              style={{
                background: theme.colors.surfaceAlt,
                border: '1px solid ' + theme.colors.border,
                borderRadius: 6,
                padding: '3px 8px',
                fontSize: 10,
                color: theme.colors.textSecondary,
                cursor: 'pointer',
                fontFamily: theme.font,
              }}
            >
              {p.name}
            </button>
          ))}
        </div>
      </div>

      {/* 3D Visualization */}
      <div
        style={{
          background: theme.colors.surface,
          borderRadius: 10,
          marginBottom: 6,
          overflow: 'hidden',
        }}
      >
        <svg
          width="100%"
          viewBox={'0 0 ' + svgW + ' ' + svgH}
          style={{ display: 'block' }}
        >
          {/* Axes */}
          {renderAxis([1, 0, 0], 'x')}
          {renderAxis([0, 1, 0], 'y')}
          {renderAxis([0, 0, 1], 'z')}

          {/* Parallelogram */}
          {showParallelogram && (
            <polygon
              points={[
                origin[0] + ',' + origin[1],
                pa[0] + ',' + pa[1],
                pab[0] + ',' + pab[1],
                pb[0] + ',' + pb[1],
              ].join(' ')}
              fill={theme.colors.primary}
              opacity={0.12}
              stroke={theme.colors.primary}
              strokeWidth={0.5}
              strokeOpacity={0.3}
              style={{ transition: 'all 0.3s ease' }}
            />
          )}

          {/* Origin */}
          <circle
            cx={origin[0]}
            cy={origin[1]}
            r={3}
            fill={theme.colors.textMuted}
          />

          {/* Vectors */}
          {renderArrow(a, theme.colors.blue, 'a', false)}
          {renderArrow(b, theme.colors.orange, 'b', false)}
          {!isZero && renderArrow(cross, theme.colors.green, 'a x b', true)}

          {/* Zero indicator */}
          {isZero && (
            <text
              x={cx}
              y={30}
              fill={theme.colors.textMuted}
              fontSize={12}
              fontFamily={theme.font}
              textAnchor="middle"
            >
              cross product = 0 (vectors are parallel)
            </text>
          )}

          {/* Magnitude label */}
          {!isZero && (
            <text
              x={svgW - 10}
              y={18}
              fill={theme.colors.textMuted}
              fontSize={10}
              fontFamily={theme.font}
              textAnchor="end"
            >
              |a x b| = {magC.toFixed(2)}
            </text>
          )}
        </svg>
      </div>

      {/* Vector Editors */}
      <div
        style={{
          display: 'flex',
          gap: 8,
          justifyContent: 'center',
          alignItems: 'center',
          marginBottom: 6,
        }}
      >
        <VecEditor label="a" vec={a} setter={setA} color={theme.colors.blue} />
        <span
          style={{
            color: theme.colors.textMuted,
            fontSize: 16,
            padding: '0 2px',
          }}
        >
          x
        </span>
        <VecEditor label="b" vec={b} setter={setB} color={theme.colors.orange} />
      </div>

      {/* Formula Breakdown */}
      <div
        style={{
          background: theme.colors.surface,
          borderRadius: 8,
          padding: '6px 10px',
          marginBottom: 6,
          display: 'flex',
          gap: 14,
          justifyContent: 'center',
          flexWrap: 'wrap',
        }}
      >
        {terms.map((t, idx) => {
          const val = t.t1[0] * t.t1[1] - t.t2[0] * t.t2[1];
          const isHov = hovered === idx;
          return (
            <div
              key={t.label}
              onMouseEnter={() => setHovered(idx)}
              onMouseLeave={() => setHovered(-1)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 4,
                fontSize: 12,
                padding: '3px 6px',
                borderRadius: 6,
                background: isHov ? theme.colors.surfaceAlt : 'transparent',
                cursor: 'default',
                transition: 'background 0.2s',
              }}
            >
              <span
                style={{
                  color: theme.colors.textMuted,
                  fontWeight: 600,
                  minWidth: 12,
                }}
              >
                {t.label}:
              </span>
              <span style={{ color: theme.colors.blue }}>
                {t.t1[0]}
              </span>
              <span style={{ color: theme.colors.textMuted }}>*</span>
              <span style={{ color: theme.colors.orange }}>
                {t.t1[1]}
              </span>
              <span style={{ color: theme.colors.textMuted }}>-</span>
              <span style={{ color: theme.colors.blue }}>
                {t.t2[0]}
              </span>
              <span style={{ color: theme.colors.textMuted }}>*</span>
              <span style={{ color: theme.colors.orange }}>
                {t.t2[1]}
              </span>
              <span style={{ color: theme.colors.textMuted }}>=</span>
              <span
                style={{
                  color: theme.colors.green,
                  fontWeight: 700,
                  fontSize: 14,
                  minWidth: 20,
                  textAlign: 'center',
                  transition: 'all 0.3s',
                }}
              >
                {val}
              </span>
            </div>
          );
        })}
      </div>

      {/* Result */}
      <div
        style={{
          textAlign: 'center',
          marginBottom: 6,
          fontSize: 13,
        }}
      >
        <span style={{ color: theme.colors.blue, fontWeight: 600 }}>a</span>
        <span style={{ color: theme.colors.textMuted }}> x </span>
        <span style={{ color: theme.colors.orange, fontWeight: 600 }}>b</span>
        <span style={{ color: theme.colors.textMuted }}> = </span>
        <span
          style={{
            color: theme.colors.green,
            fontSize: 18,
            fontWeight: 700,
            transition: 'all 0.3s',
          }}
        >
          [{cross.join(', ')}]
        </span>
      </div>

      {/* Key Insight */}
      <div
        style={{
          background: theme.colors.surfaceAlt,
          borderRadius: 8,
          padding: '7px 12px',
          fontSize: 11,
          color: theme.colors.textSecondary,
          borderLeft: '3px solid ' + theme.colors.primary,
          lineHeight: 1.4,
        }}
      >
        <span style={{ color: theme.colors.primary, fontWeight: 600 }}>
          Key:{' '}
        </span>
        {insight}
      </div>
    </div>
  );
}
